// MarkRoomAsRead is the resolver for the markRoomAsRead field.
func (r *mutationResolver) MarkRoomAsRead(ctx context.Context, input model.MarkRoomAsReadInput) (*model.MarkRoomAsReadResult, error) {
	user, err := requireAuth(ctx)
	if err != nil {
		return nil, err
	}
	kind, err := r.resolveRoomKind(ctx, input.RoomID)
	if err != nil {
		return nil, err
	}

	// Authorization: require room membership
	isMember, err := r.core.RoomMembershipExists(ctx, kind, user.Id, input.RoomID)
	if err != nil {
		return nil, err
	}
	if !isMember {
		return nil, core.ErrNotRoomMember
	}

	// Get the user's previous last-read event ID (before updating)
	previousEventID, err := r.core.GetLastReadEventID(ctx, kind, user.Id, input.RoomID)
	if err != nil {
		return nil, err
	}

	// Resolve the target event ID for the new marker. If the client passed
	// an explicit upToEventId (i.e. "I've read up to this event"), prefer
	// that — it avoids the race where messages land between subscription
	// delivery and mutation processing on the server. Otherwise fall back
	// to whatever the room's current latest root event is.
	var (
		lastEventID string
		lastTime    time.Time
		hasLast     bool
	)
	if input.UpToEventID != nil && *input.UpToEventID != "" {
		targetTime, terr := r.core.GetEventTimestamp(ctx, kind, input.RoomID, *input.UpToEventID)
		if terr != nil {
			return nil, terr
		}
		if !targetTime.IsZero() {
			lastEventID = *input.UpToEventID
			lastTime = targetTime
			hasLast = true
		}
	}
	if !hasLast {
		lastEventID, lastTime, hasLast, err = r.core.GetRoomLastEvent(ctx, kind, input.RoomID)
		if err != nil {
			return nil, err
		}
	}

	if hasLast {
		// Advance-only: don't regress the marker if the client passed a
		// stale upToEventId (e.g. another tab/device is further ahead).
		shouldWrite := true
		if previousEventID != "" && previousEventID != lastEventID {
			prevTime, perr := r.core.GetEventTimestamp(ctx, kind, input.RoomID, previousEventID)
			if perr == nil && !prevTime.IsZero() && !lastTime.After(prevTime) {
				shouldWrite = false
				lastEventID = previousEventID
				lastTime = prevTime
			}
		}
		if shouldWrite {
			if err := r.core.SetLastReadEventID(ctx, kind, user.Id, input.RoomID, lastEventID); err != nil {
				return nil, err
			}
		}
	}

	// Notify user that they marked a room as read (for space unread indicator updates)
	r.core.NotifyRoomMarkedAsRead(ctx, user.Id, kind, input.RoomID)

	// Also clear any unread mention indicator for this room
	if err := r.core.ClearMentionStatus(ctx, input.RoomID, user.Id); err != nil {
		// Log but don't fail - marking read is still successful
		r.logger.Warn("Failed to clear mention status", "space_id", kind, "room_id", input.RoomID, "error", err)
	}

	result := &model.MarkRoomAsReadResult{}

	// Resolve timestamps for the read boundaries
	if hasLast && !lastTime.IsZero() {
		result.LastReadAt = timestamppb.New(lastTime)
	}
	if previousEventID != "" {
		if t, err := r.core.GetEventTimestamp(ctx, kind, input.RoomID, previousEventID); err == nil && !t.IsZero() {
			result.PreviousLastReadAt = timestamppb.New(t)
		}
	}

	return result, nil
}

