// DeleteMessage is the resolver for the deleteMessage field.
func (r *mutationResolver) DeleteMessage(ctx context.Context, input model.DeleteMessageInput) (bool, error) {
	user, err := requireAuth(ctx)
	if err != nil {
		return false, err
	}
	kind, err := r.resolveRoomKind(ctx, input.RoomID)
	if err != nil {
		return false, err
	}

	// Authorization: check room membership
	isMember, err := r.core.RoomMembershipExists(ctx, kind, user.Id, input.RoomID)
	if err != nil {
		return false, err
	}
	if !isMember {
		return false, core.ErrNotRoomMember
	}

	// Resolve event ID to internal body key
	messageBodyKey, err := r.resolveMessageBodyKey(ctx, kind, input.RoomID, input.EventID)
	if err != nil {
		return false, err
	}

	// Authorization: check ownership and permissions
	authorID, err := r.core.GetMessageAuthorID(ctx, kind, messageBodyKey)
	if err != nil {
		return false, err
	}
	if authorID == "" {
		// Message already deleted, nothing to do
		return true, nil
	}

	if user.Id == authorID {
		// Author deleting own message: check message.delete.own permission
		can, err := r.core.CanDeleteOwnMessage(ctx, user.Id, kind, input.RoomID)
		if err != nil {
			return false, err
		}
		if !can {
			return false, core.ErrPermissionDenied
		}
	} else {
		// Non-author deleting: check message.delete-any permission AND
		// strict-outrank on the author. The rank check prevents a
		// moderator from deleting messages of higher-ranked users
		// (admins, owners) — see requireOutranksAuthor.
		can, err := r.core.CanDeleteAnyMessage(ctx, user.Id, kind, input.RoomID)
		if err != nil {
			return false, err
		}
		if !can {
			return false, core.ErrPermissionDenied
		}
		if err := r.requireOutranksAuthor(ctx, user.Id, authorID); err != nil {
			return false, err
		}
	}

	if err := r.core.DeleteMessage(ctx, user.Id, kind, input.RoomID, messageBodyKey); err != nil {
		return false, err
	}

	return true, nil
}

// EditMessage is the resolver for the editMessage field.
func (r *mutationResolver) EditMessage(ctx context.Context, input model.EditMessageInput) (bool, error) {
	user, err := requireAuth(ctx)
	if err != nil {
		return false, err
	}
	kind, err := r.resolveRoomKind(ctx, input.RoomID)
	if err != nil {
		return false, err
	}

	// Authorization: check room membership
	isMember, err := r.core.RoomMembershipExists(ctx, kind, user.Id, input.RoomID)
	if err != nil {
		return false, err
	}
	if !isMember {
		return false, core.ErrNotRoomMember
	}

	// Resolve event ID to internal body key
	messageBodyKey, err := r.resolveMessageBodyKey(ctx, kind, input.RoomID, input.EventID)
	if err != nil {
		return false, err
	}

	// Get the message to determine authorship
	messageBody, err := r.core.GetFullMessageBody(ctx, kind, messageBodyKey)
	if err != nil {
		return false, err
	}
	if messageBody == nil {
		return false, core.ErrMessageNotFound
	}

	// Authorization: two-tier permission check based on authorship
	isAuthor := messageBody.AuthorId == user.Id
	if isAuthor {
		can, err := r.core.CanEditOwnMessage(ctx, user.Id, kind, input.RoomID)
		if err != nil {
			return false, err
		}
		if !can {
			return false, core.ErrPermissionDenied
		}
		// Edit window is enforced in Core.EditMessage for author edits
	} else {
		// Non-author editing: check message.edit-any permission AND
		// strict-outrank on the author. The rank check prevents a
		// moderator from editing messages of higher-ranked users
		// (admins, owners) — see requireOutranksAuthor.
		can, err := r.core.CanEditAnyMessage(ctx, user.Id, kind, input.RoomID)
		if err != nil {
			return false, err
		}
		if !can {
			return false, core.ErrPermissionDenied
		}
		if err := r.requireOutranksAuthor(ctx, user.Id, messageBody.AuthorId); err != nil {
			return false, err
		}
	}

	if err := r.core.EditMessage(ctx, user.Id, kind, input.RoomID, messageBodyKey, input.Body); err != nil {
		return false, err
	}

	return true, nil
}

